+
+  // -----------------------------------------------------------------------
+  // DELETE
+  // -----------------------------------------------------------------------
+
+  describe("DELETE", () => {
+    it("clears all history", async () => {
+      // Seed some history
+      await POST(
+        makeRequest("http://localhost/api/history", {
+          method: "POST",
+          headers: { "Content-Type": "application/json", cookie: userCookie },
